import{Keys,pressedKey}from"../lib/accessibility.js";import{useDOM}from"../lib/dom.js";import{useIsomorphicLayoutEffect}from"../lib/useIsomorphicLayoutEffect.js";const EVENT_OPTIONS={passive:!0,capture:!0},useGlobalEscKeyDown=(s,o)=>{const t=useDOM()["document"];useIsomorphicLayoutEffect(()=>{if(t&&s&&o){const e=e=>{pressedKey(e)===Keys.ESCAPE&&o(e)};return t.addEventListener("keydown",e,EVENT_OPTIONS),()=>{t.removeEventListener("keydown",e,EVENT_OPTIONS)}}},[s,t,o])};export{useGlobalEscKeyDown};